```javascript
const loadMoreProducts = async () => {
  if (isLoadingMore || !hasMore) return;

  setIsLoadingMore(true);
  const nextPage = page + 1;
  const newProducts = await fetchProducts(nextPage, LIMIT);

  if (newProducts.length < LIMIT) setHasMore(false);
  setProducts([...products, ...newProducts]);
  setPage(nextPage);
  setIsLoadingMore(false);
};
```
La protection `if (isLoadingMore || !hasMore) return` évite les appels multiples simultanés et arrête le chargement lorsqu'il n'y a plus de données.
